class Solution:
    def replaceWords(self, dictionary, sentence):
        roots = sorted(set(dictionary), key=len)
        out = []
        for w in sentence.split(' '):
            best = w
            for r in roots:
                if w.startswith(r):
                    best = r
                    break
            out.append(best)
        return ' '.join(out)

