class Solution:
    def replaceWords(self, dictionary, sentence):
        trie = {}
        END = '#'
        for r in dictionary:
            node = trie
            for ch in r:
                node = node.setdefault(ch, {})
            node[END] = r
        def shortest(word):
            node = trie
            for ch in word:
                if ch not in node:
                    return word
                node = node[ch]
                if END in node:
                    return node[END]
            return word
        return ' '.join(shortest(w) for w in sentence.split(' '))

