var replaceWords = function(dictionary, sentence) {
    const trie = {};
    const END = '#';
    for (const r of dictionary) {
        let node = trie;
        for (const ch of r) {
            if (!node[ch]) node[ch] = {};
            node = node[ch];
        }
        node[END] = r;
    }
    const shortest = (word) => {
        let node = trie;
        for (const ch of word) {
            if (!(ch in node)) return word;
            node = node[ch];
            if (END in node) return node[END];
        }
        return word;
    };
    return sentence.split(' ').map(shortest).join(' ');
};
